20: // Open opens a connection to the db
21: func Open(cfg config.Config, logger *zap.Logger) (*sql.DB, Driver, error) {
22: 	sql, driver, err := open(cfg, logger, options{})
23: 	if err != nil {
24: 		return nil, 0, err
25: 	}
26: 
27: 	sql.SetMaxIdleConns(cfg.Database.MaxIdleConn)
28: 
29: 	if cfg.Database.MaxOpenConn > 0 {
30: 		sql.SetMaxOpenConns(cfg.Database.MaxOpenConn)
31: 	}
32: 	if cfg.Database.ConnMaxLifetime > 0 {
33: 		sql.SetConnMaxLifetime(cfg.Database.ConnMaxLifetime)
34: 	}
35: 
36: 	registerMetrics(driver, sql)
37: 
38: 	return sql, driver, nil
39: }
