46: func open(cfg config.Config, logger *zap.Logger, opts options) (*sql.DB, Driver, error) {
47: 	d, url, err := parse(cfg, logger, opts)
48: 	if err != nil {
49: 		return nil, 0, err
50: 	}
51: 
52: 	driverName := fmt.Sprintf("instrumented-%s", d)
53: 
54: 	var (
55: 		dr    driver.Driver
56: 		attrs []attribute.KeyValue
57: 	)
58: 
59: 	switch d {
60: 	case SQLite:
61: 		dr = &sqlite3.SQLiteDriver{}
62: 		attrs = []attribute.KeyValue{semconv.DBSystemSqlite}
63: 	case Postgres:
64: 		dr = &pq.Driver{}
65: 		attrs = []attribute.KeyValue{semconv.DBSystemPostgreSQL}
66: 	case CockroachDB:
67: 		dr = &pq.Driver{}
68: 		attrs = []attribute.KeyValue{semconv.DBSystemCockroachdb}
69: 	case MySQL:
70: 		dr = &mysql.MySQLDriver{}
71: 		attrs = []attribute.KeyValue{semconv.DBSystemMySQL}
72: 	}
73: 
74: 	registered := false
75: 
76: 	for _, dd := range sql.Drivers() {
77: 		if dd == driverName {
78: 			registered = true
79: 			break
80: 		}
81: 	}
82: 
83: 	if !registered {
84: 		sql.Register(driverName, otelsql.WrapDriver(dr, otelsql.WithAttributes(attrs...)))
85: 	}
86: 
87: 	db, err := sql.Open(driverName, url.DSN)
88: 	if err != nil {
89: 		return nil, 0, fmt.Errorf("opening db for driver: %s %w", d, err)
90: 	}
91: 
92: 	return db, d, nil
93: }
