130: func parse(cfg config.Config, _ *zap.Logger, opts options) (Driver, *dburl.URL, error) {
131: 	u := cfg.Database.URL
132: 
133: 	if u == "" {
134: 		host := cfg.Database.Host
135: 
136: 		if cfg.Database.Port > 0 {
137: 			host = fmt.Sprintf("%s:%d", host, cfg.Database.Port)
138: 		}
139: 
140: 		uu := url.URL{
141: 			Scheme: cfg.Database.Protocol.String(),
142: 			Host:   host,
143: 			Path:   cfg.Database.Name,
144: 		}
145: 
146: 		if cfg.Database.User != "" {
147: 			if cfg.Database.Password != "" {
148: 				uu.User = url.UserPassword(cfg.Database.User, cfg.Database.Password)
149: 			} else {
150: 				uu.User = url.User(cfg.Database.User)
151: 			}
152: 		}
153: 
154: 		u = uu.String()
155: 	}
156: 
157: 	url, err := dburl.Parse(u)
158: 	if err != nil {
159: 		return 0, nil, fmt.Errorf("error parsing url: %q, %w", url, err)
160: 	}
161: 
162: 	driver := stringToDriver[url.Unaliased]
163: 	if driver == 0 {
164: 		return 0, nil, fmt.Errorf("unknown database driver for: %q", url.Driver)
165: 	}
166: 
167: 	switch driver {
168: 	case Postgres, CockroachDB:
169: 		if opts.sslDisabled {
170: 			v := url.Query()
171: 			v.Set("sslmode", "disable")
172: 			url.RawQuery = v.Encode()
173: 			// we need to re-parse since we modified the query params
174: 			url, err = dburl.Parse(url.URL.String())
175: 		}
176: 	case MySQL:
177: 		v := url.Query()
178: 		v.Set("multiStatements", "true")
179: 		v.Set("parseTime", "true")
180: 		if !opts.migrate {
181: 			v.Set("sql_mode", "ANSI")
182: 		}
183: 		url.RawQuery = v.Encode()
184: 		// we need to re-parse since we modified the query params
185: 		url, err = dburl.Parse(url.URL.String())
186: 
187: 	case SQLite:
188: 		v := url.Query()
189: 		v.Set("cache", "shared")
190: 		v.Set("_fk", "true")
191: 		url.RawQuery = v.Encode()
192: 
193: 		// we need to re-parse since we modified the query params
194: 		url, err = dburl.Parse(url.URL.String())
195: 	}
