			driver: CockroachDB,
			dsn:    "postgres://cockroachdb@localhost:26257/flipt?sslmode=disable",
		},
		{
			name: "cockroachdb with password",
			cfg: config.DatabaseConfig{
				Protocol: config.DatabaseCockroachDB,
				Name:     "flipt",
